# slow_script.py
import time

def slow_function():
    time.sleep(1)  # Sleep 1 second
    return sum([i ** 2 for i in range(1000000)])

def fast_function():
    return sum(i ** 2 for i in range(1000000))  # No sleep, generator

print(slow_function())
print(fast_function())

