# repeated_calls.py
import requests

def fetch_data(url):
    return requests.get(url)

def process_items(items):
    results = []
    for item in items:
        # Bug: fetching same URL 1000 times!
        results.append(fetch_data("https://api.example.com/data"))
    return results

process_items([1, 2, 3, 4, 5])
